  const getList = useCallback(
    async (params?: { pageNum?: number; pageSize?: number }) => {
      return await monthlyInspectionPage({
        pageNum: params?.pageNum || 1,
        pageSize: params?.pageSize || 10,
        status: filters.status ? STATUS_KEY_TO_CODE[filters.status] : undefined,
        startDate: filters.inspectionDate?.startTime || undefined,
        endDate: filters.inspectionDate?.endTime || undefined,
      })
    },
    [filters],
  )

  const handleSubmit = (values: MonthlyInspectionFilterValues) => {
    setFilters(values || {})
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.refresh?.()
  }

  const handleCreate = () => {
    createForm.resetFields()
    setCreateVisible(true)
  }

  const handleCreateCancel = () => {
    createForm.resetFields()
    setCreateVisible(false)
  }

  const handleCreateConfirm = async () => {
    try {
      const values = await createForm.validate()
      runSave({
        inspectionDate: values.inspectionDate as string,
        inspectorIds: values.inspectorIds as (string | number)[],
      })
    } catch {
      // 表单内联校验已显示错误
    }
  }

  const isLanguageAR = getLanguage() === LanguageEnum.AR

  const handleEditMonthlyInspection = (
    record: MonthlyInspectionRecord,
    editable: boolean,
  ) => {
    const base = editable
      ? '/monthly-inspection/inspection-form'
      : '/monthly-inspection/inspection-form/view'
    navigate(`${base}/${record.inspectionId}/${record.status}`)
  }

  const columns: TableColumnProps<MonthlyInspectionRecord>[] = [
    {
      title: t('monthlyInspection:columns.inspectionId'),
      dataIndex: 'code',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: string) => value || '-',
    },
    {
      title: t('monthlyInspection:columns.inspectionDate'),
      dataIndex: 'inspectionDate',
      headerCellStyle: tableHeaderCellStyle,
    },
    {
      title: t('monthlyInspection:columns.inspector'),
      dataIndex: 'inspectorList',
      headerCellStyle: tableHeaderCellStyle,
      render: (_v, record) => {
        const data = (record.inspectorList ?? [])
          .map((item) =>
            isLanguageAR ? item.inspectorNameAr : item.inspectorName,
          )
          .filter(Boolean)
          .join(', ')
        return renderEllipsisText(data)
      },
    },
    {
      title: t('monthlyInspection:columns.issuesObserved'),
      dataIndex: 'issuesObserved',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: number | null) => (value === null ? '-' : value),
    },
    {
      title: t('monthlyInspection:columns.status'),
      dataIndex: 'status',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: MonthlyInspectionStatusEnum) => {
        const key = STATUS_CODE_TO_KEY[value]
        return (
          <span
            className={`${classPrefix}__status ${classPrefix}__status--${key}`}
          >
            <span className={`${classPrefix}__status-dot`} />
            <span>{t(`monthlyInspection:status.${key}`)}</span>
          </span>
        )
      },
    },
    {
      title: t('monthlyInspection:columns.action'),
      dataIndex: 'action',
      width: 100,
      fixed: 'right',
      headerCellStyle: tableHeaderCellStyle,
      render: (_value, record) => {
        const key = STATUS_CODE_TO_KEY[record.status]
        const editable = editableStatuses.includes(key)
        return (
          <Button
            type='text'
            size='mini'
            className={`${classPrefix}__action-btn`}
            onClick={() => handleEditMonthlyInspection(record, editable)}
            style={{ fontSize: '14px' }}
          >
            <Space size={4}>
              {editable ? <IconEdit /> : <IconEye />}
              <span>
                {t(
                  editable
                    ? 'monthlyInspection:actions.edit'
                    : 'monthlyInspection:actions.view',
                )}
              </span>
            </Space>
          </Button>
        )
      },
    },
  ]

  return (
    <div className={`${classPrefix}`}>
      <div className={`${classPrefix}-header`}>
        <div className={`${classPrefix}-title`}>
          {t('monthlyInspection:title')}
        </div>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={handleCreate}>
              {t('monthlyInspection:addButton')}
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder={t('monthlyInspection:filters.status')}
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item
              field='inspectionDate'
              normalize={(value) => ({
                startTime: value && value[0],
                endTime: value && value[1],
              })}
              formatter={(value) =>
                value && value.startTime ? [value.startTime, value.endTime] : []
              }
            >
              <DatePicker.RangePicker
                dayStartOfWeek={0}
                format='DD/MM//YYYY'
                placeholder={[
                  t('monthlyInspection:filters.dateRangeStart'),
                  t('monthlyInspection:filters.dateRangeEnd'),
                ]}
                style={{ width: 240 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
      </div>
      <div className={`${classPrefix}-table`}>
        <UnifiedTableStyle
          ref={tableRef}
          rowKey='inspectionId'
          columns={columns}
          getList={getList}
          showNoColumn={false}
          loading={true}
          showPagination={true}
          border={true}
        />
      </div>
      <Modal
        title={t('monthlyInspection:createModal.title')}
        visible={createVisible}
        onCancel={handleCreateCancel}
        maskClosable={false}
        unmountOnExit
        className={`${classPrefix}__create-modal`}
        footer={
          <Space size={12}>
            <Button icon={<IconClose />} onClick={handleCreateCancel}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              icon={<IconUpload />}
              loading={saveLoading}
              onClick={handleCreateConfirm}
            >
              {t('common:btn.create')}
            </Button>
          </Space>
        }
      >
        <Form form={createForm} layout='vertical'>
          <Form.Item
            label={t('monthlyInspection:columns.inspectionDate')}
            field='inspectionDate'
            rules={[{ required: true }]}
          >
            <DatePicker
              style={{ width: '100%' }}
              format='DD/MM/YYYY'
              placeholder={t('monthlyInspection:createModal.datePlaceholder')}
            />
          </Form.Item>
          <Form.Item
            label={t('monthlyInspection:columns.inspector')}
            field='inspectorIds'
            rules={[
              {
                required: true,
                type: 'array',
                minLength: 1,
                message: t('common:pleaseSelect'),
              },
              {
                validator: (value, cb) => {
                  if (Array.isArray(value) && value.length > MAX_INSPECTORS) {
                    cb(
                      t('monthlyInspection:messages.inspectorMaxLimit', {
                        max: MAX_INSPECTORS,
                      }),
                    )
                  } else {
                    cb()
                  }
                },
              },
            ]}
          >
            <Select
              allowClear
              showSearch
              mode='multiple'
              maxTagCount='responsive'
              options={userList}
              filterOption={(inputValue, option) =>
                String(option?.props?.children ?? '')
                  .toLowerCase()
                  .indexOf(inputValue.toLowerCase()) >= 0
              }
              placeholder={t('common:pleaseSelect')}
            />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

